mapper.select:
SELECT c.id, c.user_id as userId, c.target_type as targetType, c.target_id as targetId, c.content, c.parent_id as parentId, c.status, c.create_time as createTime, u.name as userName, u.avatar as userAvatar FROM comment c LEFT JOIN user u ON c.user_id = u.id WHERE c.target_type = #{targetType} AND c.target_id = #{targetId}
AND c.status = #{status}
ORDER BY c.create_time ASC

mapper.update:
UPDATE comment
SET status = #{status}
WHERE id = #{id}

UPDATE content_stats
SET comment_count = comment_count + 1
WHERE target_type = #{targetType}
  AND target_id = #{targetId}

mapper.select:
SELECT COUNT(*)
FROM content_stats
WHERE target_type = #{targetType}
  AND target_id = #{targetId}
